// This strategy uses a Crane-style approach where we first generate unconstrained text
// until we reach the constrained window. Once inside the constrained window, we switch
// to constrained generation. We ensure that at least one variable is present and that
// the final expression is complete and compact.
// CSD_RATIONALE_END

method MyCSDStrategy(lm: LM, parser: Parser, prompt: Prefix, maxSteps: nat, eosToken: Token) returns (generated: Prefix, remainingSteps: nat)
{
  var delim := new Delimiter(LeftDelimiter, RightDelimiter);
  var helpers := new CSDHelpers(lm, parser, delim);
  helpers.DelimitersInLMAlways();
  var stepsLeft := maxSteps;

  // Initialize generated
  var generated := [];

  // Loop until we reach the maximum number of steps or the parser is complete
  while stepsLeft > 0 && !parser.IsCompletePrefix(generated) {
    // Check if we are inside the constrained window
    if (helpers.InsideDelimitedWindow(generated) && !parser.IsCompletePrefix(helpers.GetDelimitedContent(generated))) {
      // If inside the constrained window, use constrained generation
      var next, newSteps := helpers.ConstrainedStep(prompt, generated, stepsLeft);
      generated := generated + [next];
      stepsLeft := newSteps;
    } else {
      // If outside the constrained window, use unconstrained generation
      var next, newSteps := helpers.UnconstrainedStep(prompt, generated, stepsLeft);
      generated := generated + [next];
      stepsLeft := newSteps;
    }
  }

  // If we exit the loop due to reaching maxSteps, rollback to a valid prefix
  if (stepsLeft == 0) {
    generated := helpers.RollbackToValidPrefix(generated);
  }

  // Decrement stepsLeft to account for the current step
  stepsLeft := stepsLeft - 1;

  // Ensure invariant lm.ValidTokensIdsLogits() holds
  assert lm.ValidTokensIdsLogits();

  // Ensure invariant 0 <= stepsLeft <= maxSteps
  assert 0 <= stepsLeft <= maxSteps;

  // Ensure invariant |generated| + stepsLeft == maxSteps
  assert |generated| + stepsLeft == maxSteps;

  // Ensure invariant helpers.ConstrainedWindowValid(generated)
  assert helpers.ConstrainedWindowValid(generated);

  // Ensure invariant decreases;

